CREATE OR REPLACE FUNCTION products.clone_kit(p_old_kit bigint, p_new_kit_name character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
declare
    kit_next_id                        bigint;
    kit_translation_uuid               uuid;
    f_internal_name                    varchar;
    r_old_kit                          products.kit%rowtype;
begin

    BEGIN
        select into kit_next_id nextval('products.kit_id_seq');
        select into kit_translation_uuid gen_random_uuid();
        select * into r_old_kit from products.kit where id = p_old_kit;
        f_internal_name := coalesce(p_new_kit_name, r_old_kit.internal_name || ' - clone');
        insert into products.kit (id, internal_name, main_product_code, initial_subscription_months,
                                  next_subscription_months, activation_time_days, nrc, mrc, bundle_prefix, ecommerce,
                                  category_id, translation_uuid, is_main_prd_sellable, is_active)
        values (kit_next_id, f_internal_name, r_old_kit.main_product_code, r_old_kit.initial_subscription_months,
                r_old_kit.next_subscription_months, r_old_kit.activation_time_days, r_old_kit.nrc, r_old_kit.mrc,
                f_internal_name , r_old_kit.ecommerce, r_old_kit.category_id, kit_translation_uuid,
                r_old_kit.is_main_prd_sellable, r_old_kit.is_active);


        --  insert into products.kit_customer_group (kit_id, group_id) values (kit_next_id, 1);

        -- inserisco le traduzioni di default per il kit
        insert into common.translation (translation_uuid, language, short, long)
        select kit_translation_uuid, iso,f_internal_name, ''   from common.language;

        -- copio da kit_custom_value
        insert into products.kit_custom_value (kit_id, key_name, value)
        select kit_next_id, key_name, value from products.kit_custom_value where kit_id = p_old_kit;

        -- copio da kit_product
        insert into products.kit_product (kit_id, product_code, minimum, maximum, required, nrc, mrc, position, group_name)
        select kit_next_id, product_code, minimum, maximum, required, nrc, mrc, position, group_name from products.kit_product where kit_id = p_old_kit;


    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error: %', SQLERRM;
            RETURN -1;
    END;

    return kit_next_id;
end;

$function$

CREATE OR REPLACE FUNCTION products.create_kit(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
declare
    kit_next_id                        bigint;
    kit_translation_uuid               uuid;
    kit_product_group_id               integer;
    custom_field                       json;
    customer_group                     json;
    product                            json;
    product_group                      json;
    kit_product_group_product          json;
    translation                        json;
begin
    -- kit
    select into kit_next_id nextval('products.kit_id_seq');
    select into kit_translation_uuid gen_random_uuid();
    insert into products.kit (id, internal_name, main_product_code, initial_subscription_months,
                              next_subscription_months, activation_time_days, nrc, mrc, bundle_prefix, ecommerce,
                              category_id, translation_uuid)
    values (kit_next_id, json_data ->> 'internal_name', json_data ->> 'main_product_code',
            (json_data ->> 'initial_subscription_months')::smallint, (json_data ->> 'next_subscription_months')::smallint,
            (json_data ->> 'activation_time_days')::integer, (json_data ->> 'nrc')::float8, (json_data ->> 'mrc')::float8,
            json_data ->> 'bundle_prefix', (json_data ->> 'ecommerce')::bool, (json_data ->> 'category_id')::integer, kit_translation_uuid);

    -- kit custom field
    for custom_field in select * from json_array_elements(json_data -> 'custom_fields')
        loop
            insert into products.kit_custom_value (id, kit_id, key_name, value)
            values (nextval('products.kit_custom_value_id_seq'), kit_next_id, custom_field ->> 'key_name', (custom_field ->> 'value')::jsonb);
        end loop;

      -- translation
      for translation in select * from json_array_elements(json_data->'translation' )
      loop
        insert into common.translation (translation_uuid, language, short, long)
        values (kit_translation_uuid, translation->>'language', translation->>'short', translation->>'long');
      end loop;

    -- kit customer group
    for customer_group in select * from json_array_elements( json_data -> 'customer_groups')
        loop
            insert into products.kit_customer_group ( kit_id, group_id , sellable)
            values ( kit_next_id, (customer_group ->> 'group_id')::integer , (customer_group ->> 'sellable')::bool);
        end loop;

    -- kit product
    for product in select * from json_array_elements(json_data -> 'products')
        loop
            insert into products.kit_product (id, kit_id, product_code, group_id, minimum, maximum, required, nrc, mrc)
            values (nextval('products.kit_product_id_seq'), kit_next_id, product ->> 'product_code', (product ->> 'group_id')::bigint,
                    (product ->> 'minimum')::integer,
                    (product ->> 'maximum')::integer, (product ->> 'required')::bool , (product ->> 'nrc')::float8, (product ->> 'mrc')::float8);
        end loop;

    -- kit product group
    for product_group in select * from json_array_elements(json_data -> 'product_groups')
        loop
            kit_product_group_id = nextval('products.kit_product_group_id_seq');
            insert into products.kit_product_group (id, kit_id, name, required)
            values (kit_product_group_id, kit_next_id, product_group ->> 'name', (product_group ->> 'required')::bool);
            -- kit product group product
            for kit_product_group_product in select * from json_array_elements(product_group -> 'products')
                loop
                    insert into products.kit_product (id, kit_id, product_code, group_id, minimum, maximum, required,
                                                      nrc, mrc)
                    values (nextval('products.kit_product_id_seq'), kit_next_id, kit_product_group_product ->> 'product_code',
                            kit_product_group_id, (kit_product_group_product ->> 'minimum')::integer,
                            (kit_product_group_product ->> 'maximum')::integer,
                            (kit_product_group_product ->> 'required')::bool, (kit_product_group_product ->> 'nrc')::float8,
                            (kit_product_group_product ->> 'mrc')::float8);
                end loop;
        end loop;
    return kit_next_id;
end;

$function$

CREATE OR REPLACE FUNCTION products.get_kit_customer_group(search_kit bigint)
 RETURNS json
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
 set search_path = pg_catalog,pg_temp;

select json_agg(x) from (
select group_id, name, is_partner, sellable from products.v_kit_customer_group where kit_id = search_kit
    ) x;

$function$

CREATE OR REPLACE FUNCTION products.kit_discount_get_filtered(_customer_group_id bigint, _kit_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
BEGIN

    IF _customer_group_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM customers.customer_group WHERE id = _customer_group_id) THEN
        RAISE EXCEPTION 'No customer group with id % found', _customer_group_id USING ERRCODE = 'T1BZ0';
    END IF;

    IF _kit_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM products.kit WHERE id = _kit_id) THEN
        RAISE EXCEPTION 'No kit with id % found', _kit_id USING ERRCODE = 'T1PZ0';
    END IF;

    RETURN json_agg(x)
    FROM (
        SELECT kcg.* ,
               cg.name as group_name
        FROM products.kit_customer_group kcg
        INNER JOIN customers.customer_group cg on kcg.group_id = cg.id
        WHERE
            (_customer_group_id IS NULL OR kcg.group_id = _customer_group_id) AND
            (_kit_id IS NULL OR kcg.kit_id = _kit_id)
        )x;
END;
$function$

CREATE OR REPLACE FUNCTION products.kit_get_by_id(_id bigint, _only_ecommerce boolean)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
BEGIN

    IF NOT EXISTS(SELECT 1 FROM products.kit WHERE id = _id AND (_only_ecommerce IS NULL OR _only_ecommerce IS FALSE OR ecommerce = true))
    THEN
        RAISE EXCEPTION 'No kit with id % found', _id USING ERRCODE = 'T1PZ0';
    END IF;

    RETURN json_agg(x) -> 0
    from (
        select *
        from products.v_kit_extended
        where id = _id AND
        -- only if flag is true apply filter, (filter = false) != (ecommerce = false)
        (_only_ecommerce IS NULL OR _only_ecommerce IS FALSE OR ecommerce = true)
    ) x;
END;
$function$

CREATE OR REPLACE FUNCTION products.kit_get_by_id_customer(_search_kit bigint, _customer_id bigint, _only_ecommerce boolean)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _cg_id bigint[];
    _tmp json;
BEGIN

    IF NOT EXISTS(SELECT 1 FROM customers.customer WHERE id = _customer_id) THEN
        RAISE EXCEPTION 'No customer with id % found', _customer_id USING ERRCODE = 'T1BZ0';
    END IF;

    SELECT array(
        SELECT group_id FROM customers.customer WHERE id = _customer_id
        UNION
        SELECT group_id FROM customers.group_association WHERE customer_id = _customer_id
    ) INTO _cg_id;

    -- restituisco il primo oggetto

    SELECT INTO _tmp json_agg(x) -> 0
        FROM (
            SELECT *
            FROM products.v_kit_extended_customer(_cg_id, _only_ecommerce)
            WHERE id = _search_kit
            LIMIT 1
        ) x;

    IF _tmp IS NULL THEN
        RAISE EXCEPTION 'No kit with id % found', _search_kit USING ERRCODE = 'T1PZ0';
    end if;

    RETURN _tmp;

END;
$function$

CREATE OR REPLACE FUNCTION products.new_kit(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
declare
    kit_next_id                        bigint;
    kit_translation_uuid               uuid;
    f_internal_name                    varchar;
begin

    BEGIN
        select into kit_next_id nextval('products.kit_id_seq');
        select into kit_translation_uuid gen_random_uuid();
        f_internal_name := json_data ->> 'f_internal_name';
        insert into products.kit (id, internal_name, main_product_code, initial_subscription_months,
                                  next_subscription_months, activation_time_days, nrc, mrc, bundle_prefix, ecommerce,
                                  category_id, translation_uuid)
        values (kit_next_id, f_internal_name, json_data ->> 's_main_product',
                (json_data ->> 'f_initial_subscription')::smallint, (json_data ->> 'f_next_period')::smallint,
                (json_data ->> 'f_activation_time')::integer, (json_data ->> 'f_nrc')::numeric, (json_data ->> 'f_mrc')::numeric,
                json_data ->> 'f_bundle_prefix', (json_data ->> 'sw_ecommerce')::bool, (json_data ->> 's_category')::integer, kit_translation_uuid);

        --  insert into products.kit_customer_group (kit_id, group_id) values (kit_next_id, 1);

        -- inserisco le traduzioni di default per il kit
        insert into common.translation (translation_uuid, language, short, long)
        select kit_translation_uuid, iso,f_internal_name, ''   from common.language;
    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error: %', SQLERRM;
            RETURN -1;
    END;

    return kit_next_id;
end;

$function$

CREATE OR REPLACE FUNCTION products.new_kit_product(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
declare
    kit_next_id                        bigint;
begin

    BEGIN
        select into kit_next_id nextval('products.kit_product_id_seq');

        insert into products.kit_product (id, kit_id, product_code, minimum, maximum, required, nrc, mrc, position, group_name, notes)
        values (kit_next_id, (json_data ->> 'kit_id')::bigint, json_data ->> 'product_code',
                (json_data ->> 'minimum')::smallint, (json_data ->> 'maximum')::smallint,
                (json_data ->> 'required')::bool, (json_data ->> 'nrc')::numeric, (json_data ->> 'mrc')::numeric,
                (json_data ->> 'position')::smallint , json_data ->> 'group_name', json_data ->> 'notes');
    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error: %', SQLERRM;
            RETURN -1;
    END;

    return kit_next_id;
end;

$function$

CREATE OR REPLACE FUNCTION products.validate_discount_kit_customer_group()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN

    IF NEW.discount_mrc < -1 THEN
        RAISE EXCEPTION 'discount_mrc % cannot be less than -1', NEW.discount_mrc;
    END IF;

    IF NEW.discount_nrc < -1 THEN
        RAISE EXCEPTION 'discount_nrc % cannot be less than -1', NEW.discount_nrc;
    END IF;

    RETURN NEW;
END;
$function$
